46: func wgDoneOrTimeout(wg *sync.WaitGroup, timeout time.Duration) bool {
47: 	c := make(chan struct{})
48: 	go func() {
49: 		wg.Wait()
50: 		c <- struct{}{}
51: 	}()
52: 	select {
53: 	case <-c:
54: 		return true
55: 	case <-time.After(timeout):
56: 		return false
57: 	}
58: }
