60: func TestSendPushesManyPushes(t *testing.T) {
61: 	stopCh := make(chan struct{})
62: 	defer close(stopCh)
63: 
64: 	semaphore := make(chan struct{}, 2)
65: 	queue := NewPushQueue()
66: 	defer queue.ShutDown()
67: 
68: 	proxies := createProxies(5)
69: 
70: 	pushes := make(map[string]int)
71: 	pushesMu := &sync.Mutex{}
72: 
73: 	for _, proxy := range proxies {
74: 		// Start receive thread
75: 		go func() {
76: 			for {
77: 				select {
78: 				case ev := <-proxy.PushCh():
79: 					p := ev.(*Event)
80: 					p.done()
81: 					pushesMu.Lock()
82: 					pushes[proxy.ID()]++
83: 					pushesMu.Unlock()
84: 				case <-stopCh:
85: 					return
86: 				}
87: 			}
88: 		}()
89: 	}
90: 	go doSendPushes(stopCh, semaphore, queue)
91: 
92: 	for push := 0; push < 100; push++ {
93: 		for _, proxy := range proxies {
94: 			queue.Enqueue(proxy, &model.PushRequest{Push: &model.PushContext{}, Forced: true})
95: 		}
96: 		time.Sleep(time.Millisecond * 10)
97: 	}
98: 	for queue.Pending() > 0 {
99: 		time.Sleep(time.Millisecond)
100: 	}
101: 	pushesMu.Lock()
102: 	defer pushesMu.Unlock()
103: 	for proxy, numPushes := range pushes {
104: 		if numPushes == 0 {
105: 			t.Fatalf("Proxy %v had 0 pushes", proxy)
106: 		}
107: 	}
108: }
