328: func BenchmarkPushRequest(b *testing.B) {
329: 	// allTriggers contains all triggers, so we can pick one at random.
330: 	// It is not a big issue if it falls out of sync, as we are just trying to generate test data
331: 	allTriggers := []model.TriggerReason{
332: 		model.EndpointUpdate,
333: 		model.ConfigUpdate,
334: 		model.ServiceUpdate,
335: 		model.ProxyUpdate,
336: 		model.GlobalUpdate,
337: 		model.UnknownTrigger,
338: 		model.DebugTrigger,
339: 		model.SecretTrigger,
340: 		model.NetworksTrigger,
341: 		model.ProxyRequest,
342: 		model.NamespaceUpdate,
343: 	}
344: 	// Number of (simulated) proxies
345: 	proxies := 500
346: 	// Number of (simulated) pushes merged
347: 	pushesMerged := 10
348: 	// Number of configs per push
349: 	configs := 1
350: 
351: 	for n := 0; n < b.N; n++ {
352: 		var req *model.PushRequest
353: 		for i := 0; i < pushesMerged; i++ {
354: 			trigger := allTriggers[i%len(allTriggers)]
355: 			nreq := &model.PushRequest{
356: 				ConfigsUpdated: sets.New[model.ConfigKey](),
357: 				Reason:         model.NewReasonStats(trigger),
358: 				Forced:         true,
359: 			}
360: 			for c := 0; c < configs; c++ {
361: 				nreq.ConfigsUpdated.Insert(model.ConfigKey{Kind: kind.ServiceEntry, Name: fmt.Sprintf("%d", c), Namespace: "default"})
362: 			}
363: 			req = req.Merge(nreq)
364: 		}
365: 		for p := 0; p < proxies; p++ {
366: 			recordPushTriggers(req.Reason)
367: 		}
368: 	}
369: }
