17: import (
18: 	"fmt"
19: 
20: 	discovery "github.com/envoyproxy/go-control-plane/envoy/service/discovery/v3"
21: 	"github.com/google/go-cmp/cmp"
22: 	"google.golang.org/protobuf/testing/protocmp"
23: 
