29: 
30: var knownOptimizationGaps = sets.New(
31: 	"BlackHoleCluster",
32: 	"InboundPassthroughCluster",
33: 	"PassthroughCluster",
34: )
35: 
36: // compareDiff compares a Delta and SotW XDS response. This allows checking that the Delta XDS
37: // response returned the optimal result. Checks include correctness checks (e.g. if a config changed,
38: // we must include it) and possible optimizations (e.g. we sent a config, but it was not changed).
39: func (s *DiscoveryServer) compareDiff(
40: 	con *Connection,
41: 	w *model.WatchedResource,
42: 	sotwRes model.Resources,
43: 	deltaRes model.Resources,
44: 	deleted model.DeletedResources,
45: 	usedDelta bool,
46: 	delta model.ResourceDelta,
47: 	incremental bool,
48: ) {
49: 	current := con.proxy.GetWatchedResource(w.TypeUrl).LastResources
50: 	if current == nil {
51: 		log.Debugf("ADS:%s: resources initialized", v3.GetShortType(w.TypeUrl))
52: 		return
53: 	}
54: 	if deltaRes == nil && deleted == nil && len(sotwRes) == 0 {
55: 		// TODO: it suspicious full is never nil - are there case where we should be deleting everything?
56: 		// Both SotW and Delta did not respond, nothing to compare
57: 		return
58: 	}
59: 	newByName := slices.GroupUnique(sotwRes, (*discovery.Resource).GetName)
60: 	curByName := slices.GroupUnique(current, (*discovery.Resource).GetName)
61: 
62: 	watched := w.ResourceNames
63: 
64: 	details := fmt.Sprintf("last:%v sotw:%v delta:%v-%v", len(current), len(sotwRes), len(deltaRes), len(deleted))
65: 	wantDeleted := sets.New[string]()
66: 	wantChanged := sets.New[string]()
67: 	wantUnchanged := sets.New[string]()
68: 	for _, c := range current {
69: 		n := newByName[c.Name]
70: 		if n == nil {
71: 			// We had a resource, but SotW didn't generate it.
72: 			if watched.Contains(c.Name) {
73: 				// We only need to delete it if Envoy is watching. Otherwise, it may have simply unsubscribed
74: 				wantDeleted.Insert(c.Name)
75: 			}
76: 		} else if diff := cmp.Diff(c.Resource, n.Resource, protocmp.Transform()); diff != "" {
77: 			// Resource was modified
78: 			wantChanged.Insert(c.Name)
79: 		} else {
80: 			// No diff. Ideally delta doesn't send any update here
81: 			wantUnchanged.Insert(c.Name)
82: 		}
83: 	}
84: 	for _, v := range sotwRes {
85: 		if _, f := curByName[v.Name]; !f {
86: 			// Resource is added. Delta doesn't distinguish add vs update, so just put it with changed
87: 			wantChanged.Insert(v.Name)
88: 		}
89: 	}
90: 
91: 	gotDeleted := sets.New[string]()
92: 	if usedDelta {
93: 		gotDeleted.InsertAll(deleted...)
94: 	}
95: 	gotChanged := sets.New[string]()
96: 	for _, v := range deltaRes {
97: 		gotChanged.Insert(v.Name)
98: 	}
99: 
100: 	// BUGS
101: 	extraDeletes := sets.SortedList(gotDeleted.Difference(wantDeleted))
102: 	missedDeletes := sets.SortedList(wantDeleted.Difference(gotDeleted))
103: 	missedChanges := sets.SortedList(wantChanged.Difference(gotChanged))
104: 
105: 	// Optimization Potential
106: 	extraChanges := sets.SortedList(gotChanged.Difference(wantChanged).Difference(knownOptimizationGaps))
107: 	if len(delta.Subscribed) > 0 {
108: 		// Delta is configured to build only the request resources. Make sense we didn't build anything extra
109: 		if !wantChanged.SupersetOf(gotChanged) {
110: 			log.Errorf("%s: TEST for node:%s unexpected resources: %v %v", v3.GetShortType(w.TypeUrl), con.proxy.ID, details, wantChanged.Difference(gotChanged))
111: 		}
112: 		// Still make sure we didn't delete anything extra
113: 		if len(extraDeletes) > 0 {
114: 			log.Errorf("%s: TEST for node:%s unexpected deletions: %v %v", v3.GetShortType(w.TypeUrl), con.proxy.ID, details, extraDeletes)
115: 		}
116: 	} else {
117: 		if len(extraDeletes) > 0 {
118: 			log.Errorf("%s: TEST for node:%s unexpected deletions: %v %v", v3.GetShortType(w.TypeUrl), con.proxy.ID, details, extraDeletes)
119: 		}
120: 		if len(missedDeletes) > 0 && !incremental {
121: 			// We can skip this if we are incremental; this expects us to only send a partial list. So these are not actually deletes
122: 			log.Errorf("%s: TEST for node:%s missed deletions: %v %v", v3.GetShortType(w.TypeUrl), con.proxy.ID, details, missedDeletes)
123: 		}
124: 		if len(missedChanges) > 0 {
125: 			log.Errorf("%s: TEST for node:%s missed changes: %v %v", v3.GetShortType(w.TypeUrl), con.proxy.ID, details, missedChanges)
126: 		}
127: 		if len(extraChanges) > 0 {
128: 			if usedDelta {
129: 				log.Infof("%s: TEST for node:%s missed possible optimization: %v. deleted:%v changed:%v",
130: 					v3.GetShortType(w.TypeUrl), con.proxy.ID, extraChanges, len(gotDeleted), len(gotChanged))
131: 			} else {
132: 				log.Debugf("%s: TEST for node:%s missed possible optimization: %v. deleted:%v changed:%v",
133: 					v3.GetShortType(w.TypeUrl), con.proxy.ID, extraChanges, len(gotDeleted), len(gotChanged))
134: 			}
135: 		}
136: 	}
137: }
138: 
139: func applyDelta(message model.Resources, resp *discovery.DeltaDiscoveryResponse) model.Resources {
140: 	deleted := sets.New(resp.RemovedResources...)
141: 	byName := map[string]*discovery.Resource{}
142: 	for _, v := range resp.Resources {
143: 		byName[v.Name] = v
144: 	}
145: 	res := model.Resources{}
146: 	for _, m := range message {
147: 		if deleted.Contains(m.Name) {
148: 			continue
149: 		}
150: 		if replaced := byName[m.Name]; replaced != nil {
151: 			res = append(res, replaced)
152: 			delete(byName, m.Name)
153: 			continue
154: 		}
155: 		res = append(res, m)
156: 	}
157: 	for _, v := range byName {
158: 		res = append(res, v)
159: 	}
160: 	return res
161: }
