102: // isSidecar ad-hoc method to see if connection represents a sidecar
103: func isProxy(con *Connection) bool {
104: 	return con != nil &&
105: 		con.proxy != nil &&
106: 		con.proxy.Metadata != nil &&
107: 		con.proxy.Metadata.ProxyConfig != nil
108: }
109: 
110: func isZtunnel(con *Connection) bool {
111: 	return con != nil &&
112: 		con.proxy != nil &&
113: 		con.proxy.Metadata != nil &&
114: 		con.proxy.Type == model.Ztunnel
115: }
