117: func (sg *StatusGen) debugSyncz() model.Resources {
118: 	res := model.Resources{}
119: 
120: 	for _, con := range sg.Server.Clients() {
121: 		con.proxy.RLock()
122: 		// Skip "nodes" without metadata (they are probably istioctl queries!)
123: 		if isProxy(con) || isZtunnel(con) {
124: 			xdsConfigs := make([]*status.ClientConfig_GenericXdsConfig, 0)
125: 			wrs := con.proxy.DeepCloneWatchedResources()
126: 			for _, wr := range wrs {
127: 				pxc := &status.ClientConfig_GenericXdsConfig{}
128: 				pxc.ConfigStatus = debugSyncStatus(wr)
129: 				pxc.LastUpdated = timestamppb.New(wr.LastSendTime)
130: 				pxc.TypeUrl = wr.TypeUrl
131: 				if wr.LastError != "" {
132: 					pxc.ErrorState = &admin.UpdateFailureState{
133: 						LastUpdateAttempt: timestamppb.New(wr.LastSendTime),
134: 						Details:           wr.LastError,
135: 					}
136: 				}
137: 
138: 				xdsConfigs = append(xdsConfigs, pxc)
139: 			}
140: 			slices.SortBy(xdsConfigs, func(a *status.ClientConfig_GenericXdsConfig) string {
141: 				return a.TypeUrl
142: 			})
143: 			clientConfig := &status.ClientConfig{
144: 				Node: &core.Node{
145: 					Id: con.proxy.ID,
146: 					Metadata: model.NodeMetadata{
147: 						ClusterID:    con.proxy.Metadata.ClusterID,
148: 						Namespace:    con.proxy.Metadata.Namespace,
149: 						IstioVersion: con.proxy.Metadata.IstioVersion,
150: 					}.ToStruct(),
151: 				},
152: 				GenericXdsConfigs: xdsConfigs,
153: 			}
154: 			res = append(res, &discovery.Resource{
155: 				Name:     clientConfig.Node.Id,
156: 				Resource: protoconv.MessageToAny(clientConfig),
157: 			})
158: 		}
159: 		con.proxy.RUnlock()
160: 	}
161: 
162: 	return res
163: }
164: 
165: func debugSyncStatus(wr model.WatchedResource) status.ConfigStatus {
166: 	if wr.LastError != "" {
167: 		return status.ConfigStatus_ERROR
168: 	}
169: 	if wr.NonceSent == "" {
170: 		return status.ConfigStatus_NOT_SENT
171: 	}
172: 	if wr.NonceAcked == wr.NonceSent {
173: 		return status.ConfigStatus_SYNCED
174: 	}
175: 	return status.ConfigStatus_STALE
176: }
