61: // ControlPlane identifies the instance and Istio version, based on the requested type URL
62: func ControlPlane(typ string) *core.ControlPlane {
63: 	if typ != TypeDebugSyncronization {
64: 		// Currently only TypeDebugSyncronization utilizes this so don't both sending otherwise
65: 		return nil
66: 	}
67: 	// Error will never happen because the getter of lazy does not return error.
68: 	cp, _ := controlPlane.Get()
