196: // xdsNeedsPush checks for the common cases whether we need to push or not.
197: func xdsNeedsPush(req *model.PushRequest, proxy *model.Proxy) (needsPush, definitive bool) {
198: 	if proxy.Type == model.Ztunnel {
199: 		// Not supported for ztunnel
200: 		return false, true
201: 	}
202: 	if req == nil {
203: 		return true, true
204: 	}
205: 	// If none set, we will always push
206: 	if req.Forced {
207: 		return true, true
208: 	}
209: 
210: 	// We can not definitively say if we need to push or not based on generic checks, so we will push based
211: 	// on the specific typeURL checks.
212: 	return false, false
213: }
214: 
215: // waypointNeedsPush checks if an incremental push is needed for CDS and LDS which normally do a full push.
216: func waypointNeedsPush(req *model.PushRequest) bool {
217: 	// Waypoint proxies needs to be pushed for LDS and CDS on kind.Address changes.
218: 	// Waypoint proxies have a matcher against pod IPs in them. Historically, any LDS change would do a full
219: 	// push, recomputing push context. Doing that on every IP change doesn't scale, so we need these to remain
220: 	// incremental pushes.
221: 	// This allows waypoints only to push LDS on incremental pushes to Address type which would otherwise be skipped.
222: 
223: 	// Waypoints need CDS updates on kind.Address changes
224: 	// after implementing use-waypoint which decouples waypoint creation, wl pod creation
225: 	// user specifying waypoint use. Without this we're not getting correct waypoint config
226: 	// in a timely manner
227: 	return model.HasConfigsOfKind(req.ConfigsUpdated, kind.Address)
228: }
