72: func (s *DiscoveryServer) findGenerator(typeURL string, con *Connection) model.XdsResourceGenerator {
73: 	if g, f := s.Generators[con.proxy.Metadata.Generator+"/"+typeURL]; f {
74: 		return g
75: 	}
76: 	if g, f := s.Generators[string(con.proxy.Type)+"/"+typeURL]; f {
77: 		return g
78: 	}
79: 
80: 	if g, f := s.Generators[typeURL]; f {
81: 		return g
82: 	}
83: 
84: 	// XdsResourceGenerator is the default generator for this connection. We want to allow
85: 	// some types to use custom generators - for example EDS.
86: 	g := con.proxy.XdsResourceGenerator
87: 	if g == nil {
88: 		if strings.HasPrefix(typeURL, TypeDebugPrefix) {
89: 			g = s.Generators["event"]
90: 		} else {
91: 			// TODO move this to just directly using the resource TypeUrl
92: 			g = s.Generators["api"] // default to "MCP" generators - any type supported by store
93: 		}
94: 	}
95: 	return g
96: }
