98: // Push an XDS resource for the given connection. Configuration will be generated
99: // based on the passed in generator. Based on the updates field, generators may
100: // choose to send partial or even no response if there are no changes.
101: func (s *DiscoveryServer) pushXds(con *Connection, w *model.WatchedResource, req *model.PushRequest) error {
102: 	if w == nil {
103: 		return nil
104: 	}
105: 	gen := s.findGenerator(w.TypeUrl, con)
106: 	if gen == nil {
107: 		return nil
108: 	}
109: 
110: 	t0 := time.Now()
111: 
112: 	// If delta is set, client is requesting new resources or removing old ones. We should just generate the
113: 	// new resources it needs, rather than the entire set of known resources.
114: 	// Note: we do not need to account for unsubscribed resources as these are handled by parent removal;
115: 	// See https://www.envoyproxy.io/docs/envoy/latest/api-docs/xds_protocol#deleting-resources.
116: 	// This means if there are only removals, we will not respond.
117: 	var logFiltered string
118: 	if !req.Delta.IsEmpty() && !con.proxy.IsProxylessGrpc() {
119: 		logFiltered = " filtered:" + strconv.Itoa(len(w.ResourceNames)-len(req.Delta.Subscribed))
120: 		w = &model.WatchedResource{
121: 			TypeUrl:       w.TypeUrl,
122: 			ResourceNames: req.Delta.Subscribed,
123: 		}
124: 	}
125: 	res, logdata, err := gen.Generate(con.proxy, w, req)
126: 	info := ""
127: 	if len(logdata.AdditionalInfo) > 0 {
128: 		info = " " + logdata.AdditionalInfo
129: 	}
130: 	if len(logFiltered) > 0 {
131: 		info += logFiltered
132: 	}
133: 	if err != nil || res == nil {
134: 		if log.DebugEnabled() {
135: 			log.Debugf("%s: SKIP%s for node:%s%s", v3.GetShortType(w.TypeUrl), req.PushReason(), con.proxy.ID, info)
136: 		}
137: 
138: 		return err
139: 	}
140: 	defer func() { recordPushTime(w.TypeUrl, time.Since(t0)) }()
141: 
142: 	resp := &discovery.DiscoveryResponse{
143: 		ControlPlane: ControlPlane(w.TypeUrl),
144: 		TypeUrl:      w.TypeUrl,
145: 		// TODO: send different version for incremental eds
146: 		VersionInfo: req.Push.PushVersion,
147: 		Nonce:       nonce(req.Push.PushVersion),
148: 		Resources:   xds.ResourcesToAny(res),
149: 	}
150: 
151: 	configSize := ResourceSize(res)
152: 	configSizeBytes.With(typeTag.Value(w.TypeUrl)).Record(float64(configSize))
153: 
154: 	ptype := "PUSH"
155: 	if logdata.Incremental {
156: 		ptype = "PUSH INC"
157: 	}
158: 
159: 	if err := xds.Send(con, resp); err != nil {
160: 		if recordSendError(w.TypeUrl, err) {
161: 			log.Warnf("%s: Send failure for node:%s resources:%d size:%s%s: %v",
162: 				v3.GetShortType(w.TypeUrl), con.proxy.ID, len(res), util.ByteCount(configSize), info, err)
163: 		}
164: 		return err
165: 	}
166: 
167: 	switch {
168: 	case !req.Full:
169: 		if log.DebugEnabled() {
170: 			log.Debugf("%s: %s%s for node:%s resources:%d size:%s%s",
171: 				v3.GetShortType(w.TypeUrl), ptype, req.PushReason(), con.proxy.ID, len(res), util.ByteCount(configSize), info)
172: 		}
173: 	default:
174: 		debug := ""
175: 		if log.DebugEnabled() {
176: 			// Add additional information to logs when debug mode enabled.
177: 			debug = " nonce:" + resp.Nonce + " version:" + resp.VersionInfo
178: 		}
179: 		log.Infof("%s: %s%s for node:%s resources:%d size:%v%s%s", v3.GetShortType(w.TypeUrl), ptype, req.PushReason(), con.proxy.ID, len(res),
180: 			util.ByteCount(ResourceSize(res)), info, debug)
181: 	}
182: 
183: 	return nil
184: }
