196: // xdsNeedsPush checks for the common cases whether we need to push or not.
197: func xdsNeedsPush(req *model.PushRequest, proxy *model.Proxy) (needsPush, definitive bool) {
198: 	if proxy.Type == model.Ztunnel {
199: 		// Not supported for ztunnel
200: 		return false, true
201: 	}
202: 	if req == nil {
203: 		return true, true
204: 	}
205: 	// If none set, we will always push
206: 	if req.Forced {
207: 		return true, true
208: 	}
209: 
210: 	// We can not definitively say if we need to push or not based on generic checks, so we will push based
211: 	// on the specific typeURL checks.
212: 	return false, false
213: }
