391: func (s *DiscoveryServer) cachez(w http.ResponseWriter, req *http.Request) {
392: 	if err := req.ParseForm(); err != nil {
393: 		w.WriteHeader(http.StatusBadRequest)
394: 		_, _ = w.Write([]byte("Failed to parse request\n"))
395: 		return
396: 	}
397: 	if req.Form.Get("clear") != "" {
398: 		s.Cache.ClearAll()
399: 		_, _ = w.Write([]byte("Cache cleared\n"))
400: 		return
401: 	}
402: 	if req.Form.Get("sizes") != "" {
403: 		snapshot := s.Cache.Snapshot()
404: 		raw := make(map[string]int, len(snapshot))
405: 		totalSize := 0
406: 		for _, resource := range snapshot {
407: 			if resource == nil {
408: 				continue
409: 			}
410: 			resourceType := resource.Resource.TypeUrl
411: 			sz := len(resource.Resource.GetValue())
412: 			raw[resourceType] += sz
413: 			totalSize += sz
414: 		}
415: 		res := make(map[string]string, len(raw))
416: 		for k, v := range raw {
417: 			res[k] = util.ByteCount(v)
418: 		}
419: 		res["total"] = util.ByteCount(totalSize)
420: 		writeJSON(w, res, req)
421: 		return
422: 	}
423: 	snapshot := s.Cache.Snapshot()
424: 	resources := make(map[string][]string, len(snapshot)) // Key is typeUrl and value is resource names.
425: 	for _, resource := range snapshot {
426: 		if resource == nil {
427: 			continue
428: 		}
429: 		resourceType := resource.Resource.TypeUrl
430: 		resources[resourceType] = append(resources[resourceType], resource.Name)
431: 	}
432: 	writeJSON(w, resources, req)
433: }
