1036: func (s *DiscoveryServer) ambientz(w http.ResponseWriter, req *http.Request) {
1037: 	addresses, _ := s.Env.ServiceDiscovery.AddressInformation(nil)
1038: 	res := struct {
1039: 		Workloads []jsonMarshalProto `json:"workloads"`
1040: 		Services  []jsonMarshalProto `json:"services"`
1041: 		Policies  []jsonMarshalProto `json:"policies"`
1042: 	}{}
1043: 	// WDS stores IPs as raw byte form. We want to view them as strings, so convert.
1044: 	// This doesn't quite work ideally, since json marshal will write as base64, but its better than nothing
1045: 	rewriteAddress := func(b []byte) []byte {
1046: 		ip, ok := netip.AddrFromSlice(b)
1047: 		if !ok {
1048: 			return b
1049: 		}
1050: 		return []byte(ip.String())
1051: 	}
1052: 	rewriteNetworkAddress := func(b *workloadapi.NetworkAddress) *workloadapi.NetworkAddress {
1053: 		nb := protomarshal.Clone(b)
1054: 		nb.Address = rewriteAddress(nb.Address)
1055: 		return nb
1056: 	}
1057: 	rewriteGatewayAddress := func(b *workloadapi.GatewayAddress) *workloadapi.GatewayAddress {
1058: 		if b == nil {
1059: 			return nil
1060: 		}
1061: 		nb := protomarshal.Clone(b)
1062: 		switch t := nb.Destination.(type) {
1063: 		case *workloadapi.GatewayAddress_Address:
1064: 			t.Address = rewriteNetworkAddress(t.Address)
1065: 		}
1066: 		return nb
1067: 	}
1068: 	for _, original := range addresses {
1069: 		addr := protomarshal.Clone(original.Address)
1070: 		switch addr := addr.Type.(type) {
1071: 		case *workloadapi.Address_Workload:
1072: 			w := addr.Workload
1073: 			w.Addresses = slices.Map(w.Addresses, rewriteAddress)
1074: 			w.Waypoint = rewriteGatewayAddress(w.Waypoint)
1075: 			w.NetworkGateway = rewriteGatewayAddress(w.NetworkGateway)
1076: 			res.Workloads = append(res.Workloads, jsonMarshalProto{w})
1077: 		case *workloadapi.Address_Service:
1078: 			s := addr.Service
1079: 			s.Addresses = slices.Map(s.Addresses, rewriteNetworkAddress)
1080: 			s.Waypoint = rewriteGatewayAddress(s.Waypoint)
1081: 			res.Services = append(res.Services, jsonMarshalProto{s})
1082: 		}
1083: 	}
1084: 	for _, policy := range s.Env.ServiceDiscovery.Policies(nil) {
1085: 		res.Policies = append(res.Policies, jsonMarshalProto{policy.Authorization})
1086: 	}
1087: 	writeJSON(w, res, req)
1088: }
