1148: 		// Verify namespace if caller is not from system namespace (when auth is enabled)
1149: 		if features.EnableDebugEndpointAuth {
1150: 			callerNamespace, _ := req.Context().Value(CallerNamespaceKey{}).(string)
1151: 			if con != nil && callerNamespace != "" {
1152: 				systemNamespace := constants.IstioSystemNamespace
1153: 				if s.Env != nil && s.Env.Mesh() != nil && s.Env.Mesh().GetRootNamespace() != "" {
1154: 					systemNamespace = s.Env.Mesh().GetRootNamespace()
1155: 				}
1156: 				// Non-system namespaces can only access proxies in their own namespace
1157: 				if callerNamespace != systemNamespace && con.proxy.ConfigNamespace != callerNamespace {
1158: 					return proxyID, nil // Return nil connection to deny access
1159: 				}
1160: 			}
1161: 		}
1162: 		return proxyID, con
1163: 	}
1164: 	return "", nil
1165: }
