1167: func (s *DiscoveryServer) errorHandler(w http.ResponseWriter, proxyID string, con *Connection) {
1168: 	if proxyID == "" {
1169: 		w.WriteHeader(http.StatusBadRequest)
1170: 		_, _ = w.Write([]byte("You must provide a proxyID in the query string\n"))
1171: 		return
1172: 	}
1173: 	if con == nil {
1174: 		// We can't guarantee the Pilot we are connected to has a connection to the proxy we requested
1175: 		// There isn't a great way around this, but for debugging purposes its suitable to have the caller retry.
1176: 		w.WriteHeader(http.StatusNotFound)
1177: 		_, _ = w.Write([]byte("Proxy not connected to this Pilot instance. It may be connected to another instance.\n"))
1178: 		return
1179: 	}
1180: }
