430: func initOIDC(args *PilotArgs, meshWatcher mesh.Watcher) (security.Authenticator, error) {
431: 	// JWTRule is from the JWT_RULE environment variable.
432: 	// An example of json string for JWTRule is:
433: 	// `{"issuer": "foo", "jwks_uri": "baz", "audiences": ["aud1", "aud2"]}`.
434: 	jwtRule := &v1beta1.JWTRule{}
435: 	err := json.Unmarshal([]byte(args.JwtRule), jwtRule)
436: 	if err != nil {
437: 		return nil, fmt.Errorf("failed to unmarshal JWT rule: %v", err)
438: 	}
439: 	log.Infof("Istiod authenticating using JWTRule: %v", jwtRule)
440: 	jwtAuthn, err := authenticate.NewJwtAuthenticator(jwtRule, meshWatcher)
441: 	if err != nil {
442: 		return nil, fmt.Errorf("failed to create the JWT authenticator: %v", err)
443: 	}
444: 	return jwtAuthn, nil
445: }
