601: // A single container can't have two readiness probes. Make this readiness probe a generic one
602: // that can handle all istiod related readiness checks including webhook, gRPC etc.
603: // The "http" portion of the readiness check is satisfied by the fact we've started listening on
604: // this handler and everything has already initialized.
605: func (s *Server) istiodReadyHandler(w http.ResponseWriter, _ *http.Request) {
606: 	for name, fn := range s.readinessProbes {
607: 		if ready := fn(); !ready {
608: 			log.Warnf("%s is not ready", name)
609: 			w.WriteHeader(http.StatusServiceUnavailable)
610: 			return
611: 		}
612: 	}
613: 	w.WriteHeader(http.StatusOK)
614: }
