696: // Wait for the stop, and do cleanups
697: func (s *Server) waitForShutdown(stop <-chan struct{}) {
698: 	go func() {
699: 		<-stop
700: 		close(s.internalStop)
701: 		_ = s.fileWatcher.Close()
702: 
703: 		if s.cacertsWatcher != nil {
704: 			_ = s.cacertsWatcher.Close()
705: 		}
706: 		// Stop gRPC services.  If gRPC services fail to stop in the shutdown duration,
707: 		// force stop them. This does not happen normally.
708: 		stopped := make(chan struct{})
709: 		go func() {
710: 			// Some grpcServer implementations do not support GracefulStop. Unfortunately, this is not
711: 			// exposed; they just panic. To avoid this, we will recover and do a standard Stop when its not
712: 			// support.
713: 			defer func() {
714: 				if r := recover(); r != nil {
715: 					s.grpcServer.Stop()
716: 					if s.secureGrpcServer != nil {
717: 						s.secureGrpcServer.Stop()
718: 					}
719: 					close(stopped)
720: 				}
721: 			}()
722: 			s.grpcServer.GracefulStop()
723: 			if s.secureGrpcServer != nil {
724: 				s.secureGrpcServer.GracefulStop()
725: 			}
726: 			close(stopped)
727: 		}()
728: 
729: 		t := time.NewTimer(s.shutdownDuration)
730: 		select {
731: 		case <-t.C:
732: 			s.grpcServer.Stop()
733: 			if s.secureGrpcServer != nil {
734: 				s.secureGrpcServer.Stop()
735: 			}
736: 		case <-stopped:
737: 			t.Stop()
738: 		}
739: 
740: 		// Stop HTTP services.
741: 		ctx, cancel := context.WithTimeout(context.Background(), s.shutdownDuration)
742: 		defer cancel()
743: 		if err := s.httpServer.Shutdown(ctx); err != nil {
744: 			log.Warn(err)
745: 		}
746: 		if s.httpsServer != nil {
747: 			if err := s.httpsServer.Shutdown(ctx); err != nil {
748: 				log.Warn(err)
749: 			}
750: 		}
751: 
752: 		// Shutdown the DiscoveryServer.
753: 		s.XDSServer.Shutdown()
754: 	}()
755: }
